const input = $input.first().json;
const analysisType = input.analysis_type;
const imageUrl = input.image_url;

const prompts = {
  windows: 'Analyze this exterior house photo. Identify ALL visible windows and return:
1. window_count: total count of all visible windows
2. screen_count: number of screens visible
3. stories: windows by floor {"1": count, "2": count, "3": count}
4. access_difficulty: "easy" (flat ground, standard ladder height), "moderate" (some obstacles or slope), or "difficult" (steep grade, very tall, enclosed)
5. notes: any relevant details about the windows or access

Return ONLY valid JSON — no markdown, no explanation:
{"window_count": 0, "screen_count": 0, "stories": {"1": 0, "2": 0, "3": 0}, "access_difficulty": "easy", "notes": ""}',

  concrete: 'Analyze this photo of an outdoor paved surface (driveway, patio, sidewalk, pool deck, etc.). Estimate:
1. est_sqft_min and est_sqft_max: square footage range. Reference: 1 car parking space ≈ 160 sqft; typical single-car driveway ≈ 380 sqft; typical 2-car driveway ≈ 500-600 sqft; 10x10 patio ≈ 100 sqft.
2. surface_type: "concrete", "brick", "pavers", or "mixed"
3. stain_level: "light" (mostly clean, minor dirt/pollen), "moderate" (visible staining or algae), or "heavy" (significant oil stains, heavy black algae, badly soiled)
4. notes: any relevant details

Return ONLY valid JSON — no markdown, no explanation:
{"est_sqft_min": 0, "est_sqft_max": 0, "surface_type": "concrete", "stain_level": "light", "notes": ""}',

  christmas_lights: 'Analyze this front-of-house photo to estimate Christmas light installation scope.
1. roofline_ft_min and roofline_ft_max: estimated linear feet of front-facing roofline (eave or ridge)
2. stories: number of stories (1, 2, or 3)
3. large_trees: count of trees over 6 feet tall or that would require a ladder to decorate
4. large_shrubs: count of large shrubs or bushes suitable for light wrapping
5. notes: notable features (covered porch, columns, dormers, bay windows, garage)

Return ONLY valid JSON — no markdown, no explanation:
{"roofline_ft_min": 0, "roofline_ft_max": 0, "stories": 1, "large_trees": 0, "large_shrubs": 0, "notes": ""}',

  gutters: 'Analyze this exterior house photo focusing on the gutters.
1. debris_level: "light" (minimal visible debris), "moderate" (leaves/dirt visible in gutters), or "heavy" (overflow staining, plant growth, or badly clogged appearance)
2. downspout_count: number of downspouts visible
3. visible_damage: true if gutters appear sagging, detached, rusted, or have visible gaps; false otherwise
4. notes: any relevant observations

Return ONLY valid JSON — no markdown, no explanation:
{"debris_level": "light", "downspout_count": 0, "visible_damage": false, "notes": ""}'
};

if (!prompts[analysisType]) {
  throw new Error('Unknown analysis_type: "' + analysisType + '". Must be: windows, concrete, christmas_lights, gutters');
}

if (!imageUrl) {
  throw new Error('image_url is required');
}

return [{ json: { image_url: imageUrl, analysis_type: analysisType, prompt: prompts[analysisType] } }];

const item = $input.first();
const binaryKeys = Object.keys(item.binary || {});
if (binaryKeys.length === 0) {
  throw new Error('Failed to download image — no binary data returned. Is the URL publicly accessible?');
}
const binaryKey = binaryKeys[0];
const binary = item.binary[binaryKey];
const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const base64Data = buffer.toString('base64');

const ctx = $('Build Analysis Prompt').first().json;

return [{
  json: {
    image_data: base64Data,
    image_media_type: binary.mimeType || 'image/jpeg',
    analysis_type: ctx.analysis_type,
    prompt: ctx.prompt
  }
}];

const response = $input.first().json;
const analysisType = $('Build Analysis Prompt').first().json.analysis_type;
const rawText = response.content?.[0]?.text ?? '';

let parsed;
try {
  const clean = rawText.replace(/```json\s*/gi, '').replace(/```/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  throw new Error('Vision API returned non-JSON for ' + analysisType + ': ' + rawText.substring(0, 300));
}

return [{ json: { analysis_type: analysisType, ...parsed } }];
